sql:
SELECT * 
FROM tasks 
ORDER BY due_date ASC;

SELECT title, comments
FROM tasks
WHERE assignee_id = 1;

SELECT title 
FROM tasks 
WHERE task_id IN (
    SELECT task_id 
    FROM comments
);

SELECT assignee_id, blueprint_id, MIN(due_date) AS earliest_due_date
FROM tasks
GROUP BY assignee_id, blueprint_id;

SELECT title 
FROM tasks 
WHERE task_id = 1;

